using System;
using System.Linq;
using Orchard.Caching;

namespace Orchard.Environment;

public class GacAssemblyNameResolver : IAssemblyNameResolver
{
	private readonly ICacheManager _cacheManager;

	public int Order => 30;

	public GacAssemblyNameResolver(ICacheManager cacheManager)
	{
		_cacheManager = cacheManager;
	}

	public string Resolve(string shortName)
	{
		if (_cacheManager.Get("---", (AcquireContext<string> ctx) => (from s in GetGacListForDotNet40().Split(new string[1] { "\r\n" }, StringSplitOptions.RemoveEmptyEntries)
			select s.Trim() into s
			select TrimProcessorArchitecture(s) into s
			where !string.IsNullOrWhiteSpace(s)
			select s).Distinct(StringComparer.OrdinalIgnoreCase).ToDictionary((string s) => AssemblyLoaderExtensions.ExtractAssemblyShortName(s), StringComparer.OrdinalIgnoreCase)).TryGetValue(shortName, out var value))
		{
			return value;
		}
		return null;
	}

	private static string TrimProcessorArchitecture(string value)
	{
		value = RemoveOptionalSuffix(value, ", processorArchitecture=MSIL");
		value = RemoveOptionalSuffix(value, ", processorArchitecture=AMD64");
		value = RemoveOptionalSuffix(value, ", processorArchitecture=x86");
		return value;
	}

	private static string RemoveOptionalSuffix(string value, string suffix)
	{
		if (value.EndsWith(suffix, StringComparison.OrdinalIgnoreCase))
		{
			return value.Substring(0, value.Length - suffix.Length);
		}
		return value;
	}

